SELECT h.*, ste.site_nm AS site_nm, prd.prod_nm AS prod_nm, cd_ssc.code_label AS chg_reason_cd_nm FROM pdh_prod_sku_stock_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN pd_prod prd ON prd.prod_id = h.prod_id LEFT JOIN sy_code cd_ssc ON cd_ssc.code_grp = 'SKU_STOCK_CHG' AND cd_ssc.code_value = h.chg_reason_cd
ORDER BY h.hist_id ASC ORDER BY h.hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

